// Imperative — you manage every DOM transition manually
let liked = false;
let count = 42;

document.getElementById('like-btn').addEventListener('click', () => {
  liked = !liked;
  count = liked ? count + 1 : count - 1;

  // Update every affected DOM node individually
  document.getElementById('like-btn').className = liked ? 'btn active' : 'btn';
  document.getElementById('like-btn').textContent = liked ? '♥ Unlike' : '♡ Like';
  document.getElementById('count').textContent = String(count);
  document.getElementById('icon').src = liked ? 'heart-filled.svg' : 'heart.svg';
  // If you add a 'share' button that only shows when liked — add more code here
});

// Declarative — describe each UI state, React handles transitions
function LikeButton({ initialCount }: { initialCount: number }) {
  const [liked, setLiked] = useState(false);
  const count = liked ? initialCount + 1 : initialCount;

  return (
    <div>
      <button
        className={liked ? 'btn active' : 'btn'}
        onClick={() => setLiked(!liked)}
      >
        {liked ? '♥ Unlike' : '♡ Like'}
      </button>
      <span>{count}</span>
      {/* New feature: show Share only when liked */}
      {liked && <button>Share</button>}
    </div>
  );
}

// Four possible UI states from two boolean values
// state = { loading: false, error: null, data: [...] }
function UserList({ userId }: { userId: string }) {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [users, setUsers] = useState<User[]>([]);

  // The UI is purely described by these three values
  if (loading) return <Spinner />;
  if (error) return <ErrorMessage message={error} />;
  if (users.length === 0) return <EmptyState />;
  return <ul>{users.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

// Step 1: identify components from the mockup
// SearchPage (owns: query, results)
//   SearchBar       (receives: value, onChange)
//   ResultsList     (receives: results, isLoading)
//     ResultCard    (receives: result)
//   EmptyState      (receives: query)

// Step 2: write the top-level component first
function SearchPage() {
  const [query, setQuery] = useState('');
  const { results, isLoading } = useSearch(query); // custom hook

  return (
    <div className="search-page">
      <SearchBar value={query} onChange={setQuery} />
      {isLoading && <Spinner />}
      {!isLoading && results.length === 0 && <EmptyState query={query} />}
      {!isLoading && results.length > 0 && <ResultsList results={results} />}
    </div>
  );
}

