}

// CORRECT — one source of truth, lifted to the nearest common ancestor
function ProductPage() {
  const [selectedId, setSelectedId] = useState<number | null>(null);
  return (
    <>
      <ProductList onSelect={setSelectedId} />
      <ProductDetail selectedId={selectedId} />
    </>
  );
}

function Timer() {
  const [seconds, setSeconds] = useState(0);

  useEffect(() => {
    const id = setInterval(() => setSeconds(s => s + 1), 1000);
    return () => clearInterval(id);
  }, []);

  // This function is called once per second.
  // Each call produces a fresh JSX tree with the new 'seconds' value.
  // React updates only the text node that shows the time.
  return <p>Elapsed: {seconds}s</p>;
}

// Declarative animation with CSS — works naturally with React
function Notification({ visible }: { visible: boolean }) {
  return (
    <div
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(-20px)',
        transition: 'opacity 0.2s, transform 0.2s',
      }}
    >
      Saved!
    </div>
  );
  // React just toggles the style; CSS handles the animation
}

// When using a JS animation library, you use refs to hand
// a DOM node to the library — an escape hatch from the declarative world
function FancyCard() {
  const cardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (cardRef.current) {
      // GSAP operates imperatively on the real DOM node
      gsap.from(cardRef.current, { opacity: 0, y: 30, duration: 0.4 });
    }
  }, []);

  return <div ref={cardRef}>...</div>;
}

function ChartWidget({ data }: { data: number[] }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<Chart | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;
    chartRef.current = new Chart(canvasRef.current, {
      type: 'bar',
      data: { datasets: [{ data }] },
    });
    return () => chartRef.current?.destroy(); // cleanup on unmount
  }, []); // run once on mount

  useEffect(() => {
    // Update data imperatively when prop changes
    if (chartRef.current) {
      chartRef.current.data.datasets[0].data = data;
      chartRef.current.update();
    }
  }, [data]);

  // React only owns the <canvas> shell — Chart.js owns the inside
  return <canvas ref={canvasRef} />;
}

// Three booleans allow 8 combinations, many of which are illegal
const [isSubmitting, setIsSubmitting] = useState(false);
const [isSuccess, setIsSuccess] = useState(false);
const [error, setError] = useState<string | null>(null);
// What does isSubmitting=true AND isSuccess=true mean? Undefined.

// Better: a single status string — only valid states exist
type FormStatus = 'idle' | 'submitting' | 'success' | 'error';
const [status, setStatus] = useState<FormStatus>('idle');
const [error, setError] = useState<string | null>(null);

// Render is now a clean state machine
if (status === 'submitting') return <Spinner />;
if (status === 'success') return <SuccessMessage />;
if (status === 'error') return <ErrorBanner message={error} />;
return <Form onSubmit={handleSubmit} />;

// Controlled — fully declarative, state drives the input
function EmailInput() {
  const [email, setEmail] = useState('');
  const isValid = email.includes('@');

  return (
    <>
      <input
        type="email"
        value={email}             // React controls the displayed value
        onChange={e => setEmail(e.target.value)}
      />
      {!isValid && email.length > 0 && <p>Enter a valid email</p>}
    </>
  );
}

// Uncontrolled — escape hatch, DOM owns the value
function SimpleForm() {
  const nameRef = useRef<HTMLInputElement>(null);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    console.log(nameRef.current?.value); // read on submit only
  }

  return (
    <form onSubmit={handleSubmit}>
      <input type="text" ref={nameRef} defaultValue="" />
      <button type="submit">Submit</button>
    </form>
  );
}
